import{_ as a,o,c as t,a2 as r}from"./chunks/framework.IwO0Hdn_.js";const g=JSON.parse('{"title":"[LOGIC / BUSINESS] F-04.7 — Campo URL Tutorial en Detalle de Histórico","description":"","frontmatter":{},"headers":[],"relativePath":"backlog/F-04.7_url_tutorial.md","filePath":"backlog/F-04.7_url_tutorial.md","lastUpdated":null}'),i={name:"backlog/F-04.7_url_tutorial.md"};function l(n,e,d,c,s,u){return o(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="logic-business-f-04-7-—-campo-url-tutorial-en-detalle-de-historico" tabindex="-1">[LOGIC / BUSINESS] F-04.7 — Campo URL Tutorial en Detalle de Histórico <a class="header-anchor" href="#logic-business-f-04-7-—-campo-url-tutorial-en-detalle-de-historico" aria-label="Permalink to &quot;[LOGIC / BUSINESS] F-04.7 — Campo URL Tutorial en Detalle de Histórico&quot;">​</a></h1><p><strong>Épica:</strong> EPIC-04 — Histórico de Logs Archivados</p><h2 id="🏷️-categoria" tabindex="-1">🏷️ Categoría <a class="header-anchor" href="#🏷️-categoria" aria-label="Permalink to &quot;🏷️ Categoría&quot;">​</a></h2><p><strong>Categoría:</strong> <code>Logic / Business</code><strong>Secundaria:</strong> <code>Data</code><strong>Impacta en:</strong> Equipo Fullstack (Livewire + Laravel)</p><h2 id="📦-dependencias" tabindex="-1">📦 Dependencias <a class="header-anchor" href="#📦-dependencias" aria-label="Permalink to &quot;📦 Dependencias&quot;">​</a></h2><blockquote><p>Backlogs que deben estar <strong>completados</strong> antes de implementar esta feature.</p></blockquote><table tabindex="0"><thead><tr><th>Backlog</th><th>Motivo</th></tr></thead><tbody><tr><td><a href="./F-04.1_vista_historico_pestana.html">F-04.1</a></td><td>Vista detalle del histórico (<code>/historico/{id}</code>) existente y funcional</td></tr><tr><td><a href="./F-00.2_migraciones_modelos.html">F-00.2</a></td><td>Campo <code>url_tutorial VARCHAR(500) NULLABLE</code> presente en tabla <code>archived_logs</code></td></tr></tbody></table><p><strong>Prioridad:</strong> <code>Should</code></p><hr><p><strong>Descripción:</strong> Como administrador del sistema Quiero poder añadir y editar una URL de tutorial o documentación en el detalle de un log archivado Para que cualquier persona que acceda al histórico pueda consultar directamente la documentación relacionada con ese tipo de error</p><p><strong>Criterios de Aceptación (Checklist):</strong></p><ul><li>[ ] <strong>Escenario 1 (Añadir URL):</strong> Dado que estoy en el detalle de un log del histórico y el campo <code>url_tutorial</code> está vacío, cuando escribo una URL válida en el campo y pulso &quot;Guardar&quot;, entonces la URL se persiste y se muestra como enlace clicable.</li><li>[ ] <strong>Escenario 2 (Editar URL):</strong> Dado que el campo <code>url_tutorial</code> ya tiene un valor, cuando pulso el icono de editar junto al campo, entonces el campo se vuelve editable inline; al guardar, actualiza el valor.</li><li>[ ] <strong>Escenario 3 (URL solo en Histórico):</strong> Dado que consulto el detalle de un log activo, cuando se carga la vista, entonces el campo URL Tutorial NO aparece (es exclusivo de logs archivados).</li><li>[ ] <strong>Escenario 4 (Validación URL):</strong> Dado que introduzco un texto que no es una URL válida, cuando intento guardar, entonces se muestra un error de validación (&quot;Introduce una URL válida&quot;) y no se persiste.</li><li>[ ] <strong>Escenario 5 (Enlace abre en nueva pestaña):</strong> Dado que la URL Tutorial está guardada, cuando pulso sobre ella, entonces se abre en una nueva pestaña del navegador (<code>target=&quot;_blank&quot; rel=&quot;noopener&quot;</code>).</li><li>[ ] <strong>Requisito Técnico:</strong> Campo <code>url_tutorial TEXT NULLABLE</code> en tabla <code>archived_logs</code>. Livewire Action <code>updateUrlTutorial(id, url)</code> en componente <code>ArchivedLogDetail</code>. Validación <code>url|nullable|max:500</code>. El campo es editable inline sin necesidad de un formulario separado.</li></ul><hr><p><strong>MoSCoW:</strong> <code>SHOULD</code><strong>Sprint:</strong> Sprint 3</p><p><strong>Notas:</strong></p><ul><li>Este campo se diseñó para enlazar al sistema de documentación interna (Confluence, Notion, etc.).</li><li>La idea es que el admin documente el link al procedimiento de resolución directamente en el histórico del log.</li></ul>',16)])])}const m=a(i,[["render",l]]);export{g as __pageData,m as default};
